// generar_207_signos_alerta.js
// CHIQUI Entre Señales — Nueva categoría "🚨 Signos de alerta"
//
// Qué hace este script:
// 1) app/registro-diario/page.tsx → agrega la sección "Signos de alerta"
//    (opcional, colapsada, selección múltiple). Si se marca al menos un
//    signo, el día queda en ROJO en el calendario (estado_dia = 'rojo').
// 2) app/analisis/page.tsx → nueva tarjeta "Signos de alerta" con
//    episodios por tipo y línea de tiempo sobre todo el historial,
//    más un insight si hubo eventos en los últimos 30 días.
// 3) app/vet/page.tsx → los signos aparecen en "Posible motivo de
//    consulta" (últimos 7 días), en el "Resumen clínico" (si un signo
//    se repite) y dentro de cada registro diario.
//
// IMPORTANTE: antes de correr este script, ejecuta el SQL
// sql_207_signos_alerta.sql en Supabase (New snippet), porque las
// columnas nuevas deben existir antes de que la app intente guardarlas.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_207_signos_alerta.js

const fs = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/registro-diario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/analisis/page.tsx",
    base64: ""
  },
  {
    ruta: "app/vet/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 3 archivos escritos correctamente.')
  console.log('Recuerda: primero el SQL en Supabase, luego git add / commit / push.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
